section.para:
            First, we are going to link the MobilityDB extension to the database. To do so, you need to execute the following command in your SQL editor:

CREATE EXTENSION mobilitydb CASCADE;
            We also need to set the date style to the European style, as the data is in this format. To do so, you need to execute the following command:

SET datestyle TO DMY;

The GTFS data is composed of several files, such as:


        agency.txt: the agency that operates the transportation service;


        calendar_dates.txt: exceptions for the service;


        calendar.txt: the dates for the service;


        fare_attributes.txt: the fare information;


        feed_info.txt: the feed information;


        routes.txt: the routes of the transportation service;


        shapes.txt: the shapes of the routes;


        stop_times.txt: the times of the stops;


        stops.txt: the stops of the transportation service;


        trips.txt: the trips of the transportation service.


You can find more information about the GTFS data here.

                First thing you need to do is create a MobilityDB extension, just like in the Chapter 1.
                To do so, follow this command:

CREATE EXTENSION mobilitydb CASCADE;

                Here is how to create the full tables:

DROP TABLE IF EXISTS agency CASCADE;
CREATE TABLE agency (
    agency_id text DEFAULT '',
    agency_name text DEFAULT NULL,
    agency_url text DEFAULT NULL,
    agency_timezone text DEFAULT NULL,
    agency_lang text DEFAULT NULL,
    agency_phone text DEFAULT NULL,
    agency_fare_url text DEFAULT NULL,
    agency_email text DEFAULT NULL,
    CONSTRAINT agency_pkey PRIMARY KEY (agency_id)
);

DROP TABLE IF EXISTS calendar CASCADE;
CREATE TABLE calendar (
    service_id text,
    monday int NOT NULL,
    tuesday int NOT NULL,
    wednesday int NOT NULL,
    thursday int NOT NULL,
    friday int NOT NULL,
    saturday int NOT NULL,
    sunday int NOT NULL,
    start_date date NOT NULL,
    end_date date NOT NULL,
    CONSTRAINT calendar_pkey PRIMARY KEY (service_id)
);
DROP INDEX IF EXISTS calendar_service_id;
CREATE INDEX calendar_service_id ON calendar (service_id);

DROP TABLE IF EXISTS exception_types CASCADE;
CREATE TABLE exception_types (
    exception_type int PRIMARY KEY,
    description text
);

DROP TABLE IF EXISTS calendar_dates CASCADE;
CREATE TABLE calendar_dates (
    service_id text,
    date date NOT NULL,
    exception_type int REFERENCES exception_types(exception_type)
);
DROP INDEX IF EXISTS calendar_dates_service_id;
CREATE INDEX calendar_dates_dateidx ON calendar_dates (date);

DROP TABLE IF EXISTS fare_attributes CASCADE;
CREATE TABLE fare_attributes (
    agency_id int,
    fare_id int,
    price double precision CHECK (price >= 0),
    currency_type text,
    payment_method int,
    transfers text,
    transfer_duration int,
    CONSTRAINT fare_attributes_pkey PRIMARY KEY (fare_id)
);

DROP TABLE IF EXISTS feed_info CASCADE;
CREATE TABLE feed_info (
    feed_publisher_name text,
    feed_publisher_url text,
    feed_lang text,
    feed_start_date date,
    feed_end_date date,
    feed_version int,
    feed_contact_email text,
    feed_contact_url text,
    CONSTRAINT feed_info_pkey PRIMARY KEY (feed_publisher_name)
);

DROP TABLE IF EXISTS route_types CASCADE;
CREATE TABLE route_types (
    route_type int PRIMARY KEY,
    description text
);

DROP TABLE IF EXISTS routes CASCADE;
CREATE TABLE routes (
    route_id text,
    agency_id integer,
    route_short_name text DEFAULT '',
    route_long_name text DEFAULT '',
    route_desc text DEFAULT '',
    route_type int REFERENCES route_types(route_type),
    route_url text DEFAULT NULL,
    route_color text,
    route_text_color text,
    route_sort_order integer,
    CONSTRAINT routes_pkey PRIMARY KEY (route_id)
);

DROP TABLE IF EXISTS shapes CASCADE;
CREATE TABLE shapes (
    shape_id text NOT NULL,
    shape_pt_lat double precision NOT NULL,
    shape_pt_lon double precision NOT NULL,
    shape_pt_sequence int NOT NULL,
    shape_dist_traveled float
);
DROP INDEX IF EXISTS shapes_shape_key;
CREATE INDEX shapes_shape_key ON shapes (shape_id);

DROP TABLE IF EXISTS shape_geoms CASCADE;
-- Create a table to store the shape geometries
CREATE TABLE shape_geoms (
    shape_id text NOT NULL,
    shape_geom geometry('LINESTRING', 4326),
    CONSTRAINT shape_geom_pkey PRIMARY KEY (shape_id)
);
DROP INDEX IF EXISTS shape_geoms_key;
CREATE INDEX shape_geoms_key ON shapes (shape_id);

DROP TABLE IF EXISTS location_types CASCADE;
CREATE TABLE location_types (
    location_type int PRIMARY KEY,
    description text
);

DROP TABLE IF EXISTS stops CASCADE;
CREATE TABLE stops (
    stop_id text,
    stop_code text,
    stop_name text DEFAULT NULL,
    stop_desc text DEFAULT NULL,
    stop_lat double precision,
    stop_lon double precision,
    zone_id text,
    stop_url text,
    location_type integer REFERENCES location_types(location_type),
    parent_station integer,
    wheelchair_boarding int,
    platform_code text DEFAULT NULL,
    stop_timezone text DEFAULT NULL,
    CONSTRAINT stops_pkey PRIMARY KEY (stop_id)
);

DROP TABLE IF EXISTS pickup_dropoff_types CASCADE;
CREATE TABLE pickup_dropoff_types (
    type_id int PRIMARY KEY,
    description text
);

DROP TABLE IF EXISTS stop_times CASCADE;
CREATE TABLE stop_times (
    trip_id text NOT NULL,
    -- Check that casting to time interval works.
    arrival_time interval CHECK (arrival_time::interval = arrival_time::interval),
    departure_time interval CHECK (departure_time::interval = departure_time::interval),
    stop_id text,
    stop_sequence int NOT NULL,
    stop_headsign text,
    pickup_type int REFERENCES pickup_dropoff_types(type_id),
    drop_off_type int REFERENCES pickup_dropoff_types(type_id),
    shape_dist_traveled float,
    timepoint int,
    CONSTRAINT stop_times_pkey PRIMARY KEY (trip_id, stop_sequence)
);
DROP INDEX IF EXISTS stop_times_key;
DROP INDEX IF EXISTS arr_time_index;
DROP INDEX IF EXISTS dep_time_index;
CREATE INDEX stop_times_key ON stop_times (trip_id, stop_id);
CREATE INDEX arr_time_index ON stop_times (arrival_time);
CREATE INDEX dep_time_index ON stop_times (departure_time);

DROP TABLE IF EXISTS trips CASCADE;
CREATE TABLE trips (
    route_id text NOT NULL,
    service_id text NOT NULL,
    trip_id text NOT NULL,
    trip_headsign text,
    trip_short_name text,
    direction_id int,
    block_id text,
    shape_id text,
    wheelchair_accessible int,
    bikes_allowed int,
    CONSTRAINT trips_pkey PRIMARY KEY (trip_id)
);
DROP INDEX IF EXISTS trips_trip_id;
CREATE INDEX trips_trip_id ON trips (trip_id);

Here is how to insert the description of the types for the other tables:
INSERT INTO location_types(location_type, description) VALUES (0,'stop'), (1,'station'), (2,'station entrance'), (3,'generic node'), (4,'boarding area');
INSERT INTO pickup_dropoff_types (type_id, description) VALUES (0,'Regularly Scheduled'), (1,'Not available'), (2,'Phone arrangement only'), (3,'Driver arrangement only');
INSERT INTO route_types (route_type, description) VALUES (0,'Tram, Streetcar, Light rail'), (1,'Subway, Metro'), (2,'Rail'), (3,'Bus'), (4,'Ferry'), (5,'Cable tram'), (6,'Aerial lift, Suspended cable car'), (7,'Funicular'), (11,'Trolleybus'), (12,'Monorail');

                Here is how to insert the data for the other tables:

COPY calendar(service_id,monday,tuesday,wednesday,thursday,friday,saturday,sunday, start_date,end_date) FROM '/path/to/calendar.txt' DELIMITER ',' CSV HEADER;
COPY calendar_dates(service_id,date,exception_type) FROM '/path/to/calendar_dates.txt' DELIMITER ',' CSV HEADER;
COPY fare_attributes(agency_id, fare_id, price, currency_type, payment_method, transfers, transfer_duration) FROM '/path/to/fare_attributes.txt' DELIMITER ',' CSV HEADER;
COPY feed_info(feed_publisher_name,feed_publisher_url,feed_lang,feed_start_date,feed_end_date,feed_version, feed_contact_email, feed_contact_url) FROM '/path/to/feed_info.txt' DELIMITER ',' CSV HEADER;
COPY routes(route_id,agency_id, route_short_name,route_long_name,route_desc,route_type,route_url, route_color,route_text_color, route_sort_order) FROM '/path/to/routes.txt' DELIMITER ',' CSV HEADER;
COPY shapes(shape_id,shape_pt_lat,shape_pt_lon,shape_pt_sequence, shape_dist_traveled) FROM '/path/to/shapes.txt' DELIMITER ',' CSV HEADER;
COPY stops(stop_id,stop_code,stop_name,stop_desc,stop_lat,stop_lon,zone_id,stop_url, location_type,parent_station,wheelchair_boarding,platform_code,stop_timezone) FROM '/path/to/stops.txt' DELIMITER ',' CSV HEADER;
COPY stop_times(trip_id,arrival_time,departure_time,stop_id,stop_sequence,stop_headsign,pickup_type,drop_off_type,shape_dist_traveled,timepoint) FROM '/path/to/stop_times.txt' DELIMITER ',' CSV HEADER;
COPY trips(route_id,service_id,trip_id,trip_headsign,trip_short_name,direction_id,block_id,shape_id,wheelchair_accessible,bikes_allowed) FROM '/path/to/trips.txt' DELIMITER ',' CSV HEADER;
                You can also find the copyGTFS.sh script that indicates how to copy the data in the tables using command line in the repository.
                If you do so, please make sure that your database is nammed "star", or modify your copy of the script.
